import{_ as i,o as l,c as o,ae as a}from"./chunks/framework.RRduUuAx.js";const m=JSON.parse('{"title":"Unified Model + Provider Ledger Plan (2026-02-21)","description":"","frontmatter":{},"headers":[],"relativePath":"fragemented/plans/UNIFIED_MODEL_PROVIDER_LEDGER_PLAN_2026-02-21.md","filePath":"fragemented/plans/UNIFIED_MODEL_PROVIDER_LEDGER_PLAN_2026-02-21.md"}'),r={name:"fragemented/plans/UNIFIED_MODEL_PROVIDER_LEDGER_PLAN_2026-02-21.md"};function t(n,e,d,s,c,p){return l(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="unified-model-provider-ledger-plan-2026-02-21" tabindex="-1">Unified Model + Provider Ledger Plan (2026-02-21) <a class="header-anchor" href="#unified-model-provider-ledger-plan-2026-02-21" aria-label="Permalink to &quot;Unified Model + Provider Ledger Plan (2026-02-21)&quot;">​</a></h1><h2 id="objective" tabindex="-1">Objective <a class="header-anchor" href="#objective" aria-label="Permalink to &quot;Objective&quot;">​</a></h2><p>Create one canonical ledger that joins:</p><ol><li>Provider/model pricing data,</li><li>model benchmark priors,</li><li>mapping provenance (rules/confidence),</li><li>runtime telemetry feeder compatibility (including cliproxyapi/OTEL-normalized usage).</li></ol><h2 id="inputs" tabindex="-1">Inputs <a class="header-anchor" href="#inputs" aria-label="Permalink to &quot;Inputs&quot;">​</a></h2><ol><li><code>pricing.example.json</code></li><li><code>models_normalized.csv</code></li><li>Ingested normalized JSONL events (including <code>provider=proxyapi</code>)</li></ol><h2 id="outputs" tabindex="-1">Outputs <a class="header-anchor" href="#outputs" aria-label="Permalink to &quot;Outputs&quot;">​</a></h2><ol><li><code>ledger/unified_model_provider_ledger.csv</code></li><li><code>ledger/unified_model_provider_ledger.schema.sql</code></li><li><code>ledger/unified_model_provider_ledger.seed.sql</code></li></ol><h2 id="generation-pipeline" tabindex="-1">Generation pipeline <a class="header-anchor" href="#generation-pipeline" aria-label="Permalink to &quot;Generation pipeline&quot;">​</a></h2><ol><li>Parse pricing and canonical provider/model maps.</li><li>Parse normalized model benchmark rows.</li><li>Infer provider and canonical model candidates for each source model.</li><li>Attach benchmark priors and pricing deltas.</li><li>Emit CSV + SQL schema + SQL inserts.</li></ol><h2 id="mapping-methodology" tabindex="-1">Mapping methodology <a class="header-anchor" href="#mapping-methodology" aria-label="Permalink to &quot;Mapping methodology&quot;">​</a></h2><ol><li>Provider mapping:</li></ol><ul><li>deterministic token/prefix-based heuristics,</li><li>explicit <code>provider_mapping_rule</code>,</li><li>integer <code>provider_mapping_confidence</code>.</li></ul><ol start="2"><li>Model mapping:</li></ol><ul><li>exact pricing model match first,</li><li>alias/model-family heuristics second,</li><li>explicit <code>model_mapping_rule</code>,</li><li>integer <code>model_mapping_confidence</code>.</li></ul><ol start="3"><li>Unknown/unmapped models:</li></ol><ul><li>retained in output with null pricing,</li><li>benchmark priors preserved for analysis.</li></ul><h2 id="runtime-integration-scope" tabindex="-1">Runtime integration scope <a class="header-anchor" href="#runtime-integration-scope" aria-label="Permalink to &quot;Runtime integration scope&quot;">​</a></h2><ol><li><code>tokenledger ingest --provider proxyapi</code> emits normalized JSONL from cliproxyapi/OTEL and usage payloads.</li><li>Runtime events join to ledger on canonicalized provider/model.</li><li>Blended cost + benchmark-aware Pareto scoring can be computed from unified rows.</li></ol><h2 id="governance" tabindex="-1">Governance <a class="header-anchor" href="#governance" aria-label="Permalink to &quot;Governance&quot;">​</a></h2><ol><li>Ledger artifacts are generated, not manually edited.</li><li>Regeneration command must be deterministic.</li><li>Mapping confidence/rule fields are mandatory for auditability.</li><li>SQL seed must load cleanly in SQLite checks.</li></ol><h2 id="execution-checklist" tabindex="-1">Execution checklist <a class="header-anchor" href="#execution-checklist" aria-label="Permalink to &quot;Execution checklist&quot;">​</a></h2><ol><li>Run generator:</li></ol><ul><li><code>python3 ./scripts/build_unified_ledger.py</code></li></ul><ol start="2"><li>Validate load:</li></ol><ul><li><code>sqlite3 :memory: &quot;.read ./ledger/unified_model_provider_ledger.schema.sql&quot; &quot;.read ./ledger/unified_model_provider_ledger.seed.sql&quot; &quot;SELECT COUNT(*) FROM unified_model_provider_ledger;&quot;</code></li></ul><ol start="3"><li>Validate feeder:</li></ol><ul><li><code>cargo run -- ingest --provider proxyapi --output ./artifacts/proxyapi-events.jsonl</code></li></ul><ol start="4"><li>Validate end-to-end orchestrate:</li></ol><ul><li><code>cargo run -- orchestrate --providers proxyapi --events-out ./artifacts/proxyapi-events.jsonl --summary-json-path ./benchmarks/results/ingest-summary.json --ingest-cache-path ./benchmarks/results/orchestrate-ingest-cache.json --pipeline-summary-path ./benchmarks/results/orchestrate-summary.json --pricing-reconcile-dry-run</code></li></ul><h2 id="closeout-update-2026-02-21" tabindex="-1">Closeout update (2026-02-21) <a class="header-anchor" href="#closeout-update-2026-02-21" aria-label="Permalink to &quot;Closeout update (2026-02-21)&quot;">​</a></h2><ol><li>ProxyAPI feeder validation taskchain is now explicit and repeatable:</li></ol><ul><li><code>task ingest:proxyapi:validate</code></li><li><code>task orchestrate:proxyapi:validate</code></li><li><code>task ledger:proxyapi:e2e:validate</code> (runs both in sequence)</li></ul><ol start="2"><li>End-to-end orchestrate validation now persists summary artifacts under:</li></ol><ul><li><code>benchmarks/results/proxyapi-ingest-summary.json</code></li><li><code>benchmarks/results/proxyapi-orchestrate-summary.json</code></li><li><code>benchmarks/results/proxyapi-ui-snapshot.json</code></li></ul>',35)])])}const h=i(r,[["render",t]]);export{m as __pageData,h as default};
